mapper.select:
SELECT run.*, users.name AS user_name, users.email AS user_email, ( SELECT COUNT(*) FROM admin_career_run_memo memo_count_source WHERE memo_count_source.career_analysis_run_id = run.id ) AS memo_count, ( SELECT MAX(latest_memo.updated_at) FROM admin_career_run_memo latest_memo WHERE latest_memo.career_analysis_run_id = run.id ) AS latest_memo_at FROM career_analysis_run run INNER JOIN users ON users.id = run.user_id
WHERE run.user_id = #{userId}
ORDER BY run.created_at DESC, run.id DESC LIMIT 300

mapper.update:
UPDATE admin_career_run_memo
SET memo_type = #{memoType},
    content = #{content}
WHERE id = #{id}
  AND career_analysis_run_id = #{careerAnalysisRunId}

mapper.delete:
DELETE FROM admin_career_run_memo
WHERE id = #{id}
  AND career_analysis_run_id = #{runId}
